const POSTAGE = {
  light:  { kg: 3,  t: [{v:150,c:10},{v:750,c:14.25},{v:1000,c:17.25},{v:2500,c:24.25}] },
  medium: { kg: 10, t: [{v:150,c:10},{v:750,c:19.75},{v:1000,c:22.75},{v:2500,c:29.75}] },
  heavy:  { kg: 30, t: [{v:150,c:10},{v:750,c:23.75},{v:1000,c:26.75},{v:2500,c:33.75}] },
};
function getPostage(kg, val) {
  const b = kg <= 3 ? POSTAGE.light : kg <= 10 ? POSTAGE.medium : POSTAGE.heavy;
  for (const t of b.t) if (val <= t.v) return t.c;
  return b.t[b.t.length-1].c;
}
