                  <button onClick={() => addToCart(selItem)} className="ab" style={{ width: "100%", padding: 14, borderRadius: 50, background: `linear-gradient(135deg,${C.m},${C.md})`, color: "#fff", fontWeight: 700, fontSize: 15, border: "none", cursor: "pointer", fontFamily: f }}>+ Add to Cart</button>
